/**
 * Hierarchical Swarm Production Validation Script
 * Production-Validator Agent Implementation
 * Mission: Validate both fixes working together in production environment
 * Generated by: Production-Validator Agent
 */

const puppeteer = require('puppeteer');
const fetch = require('node-fetch');
const fs = require('fs');
const path = require('path');

class HierarchicalSwarmValidator {
  constructor() {
    this.browser = null;
    this.page = null;
    this.baseUrl = 'http://localhost:5173';
    this.backendUrl = 'http://localhost:3000';
    this.results = {
      timestamp: new Date().toISOString(),
      optionA: { status: 'pending', details: [] },
      optionC: { status: 'pending', details: [] },
      hybrid: { status: 'pending', details: [] },
      overall: { status: 'pending', score: 0 }
    };
  }

  async initialize() {
    console.log('🚀 Initializing Hierarchical Swarm Production Validator...');
    
    // Check backend health
    try {
      const healthResponse = await fetch(`${this.backendUrl}/health`);
      const health = await healthResponse.json();
      console.log('✅ Backend health check passed:', health.message);
    } catch (error) {
      throw new Error(`Backend not available: ${error.message}`);
    }

    // Launch browser
    this.browser = await puppeteer.launch({
      headless: false, // Show browser for debugging
      defaultViewport: { width: 1280, height: 720 },
      args: ['--no-sandbox', '--disable-dev-shm-usage']
    });

    this.page = await this.browser.newPage();
    
    // Enable console logging
    this.page.on('console', msg => {
      console.log(`🖥️  BROWSER: ${msg.text()}`);
    });
    
    // Enable error logging
    this.page.on('pageerror', error => {
      console.error('❌ BROWSER ERROR:', error.message);
    });

    await this.page.goto(this.baseUrl);
    console.log('📱 Frontend loaded');
  }

  async validateOptionA() {
    console.log('\\n🔍 Validating Option A: Instance List Refresh');
    
    try {
      // Wait for ClaudeInstanceManager to load
      await this.page.waitForSelector('.claude-instance-manager', { timeout: 10000 });
      console.log('✅ ClaudeInstanceManager loaded');

      // Check initial state - should be no instances
      const initialInstances = await this.page.$$('.instance-item');
      console.log(`📋 Initial instances count: ${initialInstances.length}`);

      // Test all 4 buttons
      const buttons = [
        { selector: 'button:has-text("🚀 prod/claude")', name: 'prod/claude' },
        { selector: 'button:has-text("⚡ skip-permissions")', name: 'skip-permissions' },
        { selector: 'button:has-text("⚡ skip-permissions -c")', name: 'skip-permissions -c' },
        { selector: 'button:has-text("↻ skip-permissions --resume")', name: 'skip-permissions --resume' }
      ];

      for (const button of buttons) {
        console.log(`\\n🔄 Testing button: ${button.name}`);
        
        // Click the button
        await this.page.click(button.selector);
        console.log(`✅ Clicked ${button.name} button`);

        // Wait for API call to complete and instance to appear in list
        await this.page.waitForTimeout(2000); // Give time for fetchInstances() to complete
        
        // Check if instance appears in list (Option A validation)
        const instancesAfterCreate = await this.page.$$('.instance-item');
        
        if (instancesAfterCreate.length > initialInstances.length) {
          console.log(`✅ Instance list refreshed successfully for ${button.name}`);
          this.results.optionA.details.push({
            button: button.name,
            status: 'success',
            message: 'Instance appeared in list after button click'
          });
        } else {
          console.log(`❌ Instance list did not refresh for ${button.name}`);
          this.results.optionA.details.push({
            button: button.name,
            status: 'failure',
            message: 'Instance did not appear in list after button click'
          });
        }
      }

      // Check if all buttons created instances
      const finalInstances = await this.page.$$('.instance-item');
      const expectedInstances = buttons.length;
      
      if (finalInstances.length >= expectedInstances) {
        this.results.optionA.status = 'success';
        console.log(`✅ Option A validation passed: ${finalInstances.length}/${expectedInstances} instances visible`);
      } else {
        this.results.optionA.status = 'failure';
        console.log(`❌ Option A validation failed: ${finalInstances.length}/${expectedInstances} instances visible`);
      }

    } catch (error) {
      console.error('❌ Option A validation error:', error);
      this.results.optionA.status = 'error';
      this.results.optionA.details.push({
        error: error.message,
        stack: error.stack
      });
    }
  }

  async validateOptionC() {
    console.log('\\n🔍 Validating Option C: Terminal Input Echo');
    
    try {
      // Select the first available instance
      const instanceItems = await this.page.$$('.instance-item');
      if (instanceItems.length === 0) {
        throw new Error('No instances available for terminal testing');
      }

      // Click on the first instance
      await instanceItems[0].click();
      console.log('✅ Selected first instance for terminal testing');

      // Wait for terminal interface to appear
      await this.page.waitForSelector('.input-field', { timeout: 5000 });
      console.log('✅ Terminal input field found');

      // Test terminal input echo
      const testInputs = ['hello', 'ls', 'echo test', 'pwd'];
      
      for (const input of testInputs) {
        console.log(`\\n⌨️  Testing terminal input: "${input}"`);
        
        // Clear and type input
        await this.page.click('.input-field');
        await this.page.keyboard.selectAll();
        await this.page.type('.input-field', input);
        
        // Press Enter
        await this.page.keyboard.press('Enter');
        console.log(`✅ Sent input: "${input}"`);

        // Wait for response and check if echo appears
        await this.page.waitForTimeout(1000);
        
        // Check if input echo appears in output area
        const outputText = await this.page.$eval('.output-area pre', el => el.textContent);
        
        if (outputText && outputText.includes(input)) {
          console.log(`✅ Terminal echo working for: "${input}"`);
          this.results.optionC.details.push({
            input,
            status: 'success',
            message: `Echo appeared in terminal output`
          });
        } else {
          console.log(`❌ Terminal echo failed for: "${input}"`);
          this.results.optionC.details.push({
            input,
            status: 'failure',
            message: `Echo did not appear in terminal output`
          });
        }
      }

      // Check success rate
      const successfulTests = this.results.optionC.details.filter(d => d.status === 'success').length;
      const totalTests = testInputs.length;
      
      if (successfulTests >= totalTests * 0.75) { // 75% success rate
        this.results.optionC.status = 'success';
        console.log(`✅ Option C validation passed: ${successfulTests}/${totalTests} inputs echoed`);
      } else {
        this.results.optionC.status = 'failure';
        console.log(`❌ Option C validation failed: ${successfulTests}/${totalTests} inputs echoed`);
      }

    } catch (error) {
      console.error('❌ Option C validation error:', error);
      this.results.optionC.status = 'error';
      this.results.optionC.details.push({
        error: error.message,
        stack: error.stack
      });
    }
  }

  async validateHybridSolution() {
    console.log('\\n🔍 Validating Hybrid Solution: Option A + C Integration');
    
    try {
      // Test complete workflow: Create instance → Instance appears → Terminal works
      console.log('🔄 Testing complete workflow...');
      
      // Get initial instance count
      const initialInstances = await this.page.$$('.instance-item');
      
      // Create new instance
      await this.page.click('button:has-text("🚀 prod/claude")');
      console.log('✅ Created new instance via button');
      
      // Wait for instance to appear (Option A)
      await this.page.waitForTimeout(2000);
      const newInstances = await this.page.$$('.instance-item');
      
      if (newInstances.length > initialInstances.length) {
        console.log('✅ Instance appeared in list (Option A working)');
        
        // Select the new instance
        await newInstances[newInstances.length - 1].click();
        console.log('✅ Selected new instance');
        
        // Wait for terminal to be ready
        await this.page.waitForTimeout(1000);
        
        // Test terminal input (Option C)
        await this.page.click('.input-field');
        await this.page.type('.input-field', 'hybrid test');
        await this.page.keyboard.press('Enter');
        console.log('✅ Sent terminal input to new instance');
        
        // Check if echo appears
        await this.page.waitForTimeout(1000);
        const outputText = await this.page.$eval('.output-area pre', el => el.textContent);
        
        if (outputText && outputText.includes('hybrid test')) {
          this.results.hybrid.status = 'success';
          console.log('✅ Hybrid solution validation passed: Complete workflow working');
          this.results.hybrid.details.push({
            workflow: 'create-instance-use-terminal',
            status: 'success',
            message: 'Complete workflow from button click to terminal echo successful'
          });
        } else {
          this.results.hybrid.status = 'failure';
          console.log('❌ Hybrid solution validation failed: Terminal not working after instance creation');
          this.results.hybrid.details.push({
            workflow: 'create-instance-use-terminal',
            status: 'failure',
            message: 'Terminal echo failed after instance creation'
          });
        }
      } else {
        this.results.hybrid.status = 'failure';
        console.log('❌ Hybrid solution validation failed: Instance did not appear in list');
        this.results.hybrid.details.push({
          workflow: 'create-instance-use-terminal',
          status: 'failure',
          message: 'Instance creation did not refresh list'
        });
      }

    } catch (error) {
      console.error('❌ Hybrid solution validation error:', error);
      this.results.hybrid.status = 'error';
      this.results.hybrid.details.push({
        error: error.message,
        stack: error.stack
      });
    }
  }

  calculateScore() {
    let score = 0;
    const maxScore = 100;
    
    // Option A scoring (40 points)
    if (this.results.optionA.status === 'success') {
      const successfulButtons = this.results.optionA.details.filter(d => d.status === 'success').length;
      score += (successfulButtons / 4) * 40;
    }
    
    // Option C scoring (40 points)
    if (this.results.optionC.status === 'success') {
      const successfulInputs = this.results.optionC.details.filter(d => d.status === 'success').length;
      score += (successfulInputs / 4) * 40;
    }
    
    // Hybrid solution scoring (20 points)
    if (this.results.hybrid.status === 'success') {
      score += 20;
    }
    
    this.results.overall.score = Math.round(score);
    this.results.overall.status = score >= 80 ? 'success' : score >= 50 ? 'partial' : 'failure';
  }

  async cleanup() {
    if (this.browser) {
      await this.browser.close();
    }
    console.log('🧹 Cleanup completed');
  }

  async generateReport() {
    this.calculateScore();
    
    const report = {
      title: 'Hierarchical Swarm Production Validation Report',
      ...this.results,
      summary: {
        optionA: `Instance list refresh: ${this.results.optionA.status}`,
        optionC: `Terminal input echo: ${this.results.optionC.status}`,
        hybrid: `Integrated workflow: ${this.results.hybrid.status}`,
        score: `${this.results.overall.score}/100`,
        recommendation: this.results.overall.score >= 80 ? 
          'APPROVED FOR DEPLOYMENT' : 
          this.results.overall.score >= 50 ?
            'REQUIRES FIXES BEFORE DEPLOYMENT' :
            'MAJOR ISSUES - DO NOT DEPLOY'
      }
    };

    // Save report
    const reportPath = path.join(__dirname, '../../../docs/HIERARCHICAL_SWARM_VALIDATION_REPORT.json');
    fs.writeFileSync(reportPath, JSON.stringify(report, null, 2));
    console.log(`\\n📊 Report saved to: ${reportPath}`);
    
    return report;
  }

  async run() {
    console.log('🤖 Starting Hierarchical Swarm Production Validation');
    console.log('Mission: Validate Option A (fetchInstances callbacks) + Option C (terminal echo) working together');
    
    try {
      await this.initialize();
      
      // Run validations concurrently where possible
      await this.validateOptionA();
      await this.validateOptionC();
      await this.validateHybridSolution();
      
      const report = await this.generateReport();
      
      // Print summary
      console.log('\\n' + '='.repeat(60));
      console.log('📊 HIERARCHICAL SWARM VALIDATION RESULTS');
      console.log('='.repeat(60));
      console.log(`Option A (Instance List): ${report.summary.optionA}`);
      console.log(`Option C (Terminal Echo): ${report.summary.optionC}`);
      console.log(`Hybrid Solution: ${report.summary.hybrid}`);
      console.log(`Overall Score: ${report.summary.score}`);
      console.log(`Recommendation: ${report.summary.recommendation}`);
      console.log('='.repeat(60));
      
      return report;
      
    } catch (error) {
      console.error('❌ Validation failed:', error);
      throw error;
    } finally {
      await this.cleanup();
    }
  }
}

// Run validation if called directly
if (require.main === module) {
  const validator = new HierarchicalSwarmValidator();
  validator.run()
    .then(report => {
      console.log('\\n✅ Validation completed successfully');
      process.exit(report.overall.score >= 80 ? 0 : 1);
    })
    .catch(error => {
      console.error('\\n❌ Validation failed:', error);
      process.exit(1);
    });
}

module.exports = HierarchicalSwarmValidator;